        .underline {
            position: relative;
            text-decoration: none;
            /* Remove the default underline */
        }

        .underline::after {
            content: "";
            position: absolute;
            left: 0;
            bottom: 0;
            /* Align underline to text's bottom */
            width: 100%;
            height: 16px;
            /* Thickness of the underline */
