            color: #ffbd41a8;
        }

        a.th-btn.style-radius {
            position: relative;
            display: inline-flex;
            align-items: center;
            vertical-align: middle;
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            outline: none !important;
            padding: 10px 15px 10px 16px;
            letter-spacing: 1.6px;
            border-radius: 30px;
            transition: all 0.5s linear;
            overflow: hidden;
            gap: 10px;
            z-index: 1;
        }

        .th-btn.style-radius:after {
            content: "";
            background-color: var(--onpoint-black);
            position: absolute;
            transition: all 0.3s ease-in;
            z-index: -1;
            height: 100%;
            left: -35%;
            top: 0;
            transform: skew(30deg);
            transition-duration: 0.6s;
            transform-origin: top left;
            width: 0;
        }

        .th-btn.style-radius:hover:after {
            height: 100%;
            width: 135%;
        }

        .th-btn.style-radius:hover>span:after {
            animation: bounceright 0.3s ease infinite alternate;
        }

        .th-btn.style-radius:hover {
            color: var(--onpoint-white);
        }

        .see-all {
            float: right;
            gap: 10px;
        }

        .see-all {
            display: inline-flex;
            align-items: center;
            position: relative;
            text-decoration: none;
        }

        /* Initial state of the icon */
        .see-all i {
            transition: transform 2.3s ease-in-out;
            /* Smooth transition */
        }

        /* Define the vibration effect */
        @keyframes vibrate {
            0% {
                transform: translateX(0);
            }

            25% {
                transform: translateX(-3px);
            }

            50% {
                transform: translateX(3px);
            }

            75% {
                transform: translateX(-3px);
            }

            100% {
                transform: translateX(3px);
            }
        }

        /* Hover effect to trigger the vibration */
        .see-all:hover i {
            animation: vibrate 2.3s ease-in-out infinite;
        }

