        /* Example media queries for responsiveness */
        @media (max-width: 1024px) {
            .hero-lead-part {
                top: 25%;
                /* Adjust vertical position for tablets */
            }
        }

        @media (max-width: 768px) {
            .hero-lead-part {
                top: 30%;
                /* Adjust for smaller devices */
            }
        }

        @media (max-width: 480px) {
            .hero-lead-part {
                top: 35%;
                /* Adjust for very small devices */
            }
        }

        /* Adjustments for screens with max width of 1400px */
        @media (max-width: 1400px) {
            .hero-lead-part {
                right: 1%;
                top: 20%;
            }
        }

        /* Adjustments for medium to small screens (up to 1200px) */
        @media (max-width: 1200px) {
            .hero-lead-part {
                left: 55%;
                /* Adjust the position for larger screens */
                top: 20%;
                /* Adjust the vertical position */
            }
        }

        /* Adjustments for smaller screens (up to 992px) */
        @media (max-width: 992px) {
            .hero-lead-part {
                left: 50%;
                /* Adjust the position for medium screens */
                top: 25%;
                /* Adjust the vertical position */
                transform: translateX(-50%);
                /* Center horizontally */
            }
        }

        /* Adjustments for even smaller screens (up to 768px) */
        @media (max-width: 768px) {
            .hero-lead-part {
                left: 40%;
